public int countClumps(int[] nums) {
    int clumps = 0;
    boolean isClump = false;

    for (int i = 1; i < nums.length; i++) {
        if (nums[i] == nums[i - 1]) {
            isClump = true;
        } else {
            if (isClump) {
                clumps++;
                isClump = false;
            }
        }
    }

    if (isClump) {
        clumps++;
    }

    return clumps;
}

